const CockpitManager = require\('/opt/moltagent/src/lib/integrations/cockpit-manager'\);

// Patch bootstrap to add logging
const original = CockpitManager.prototype.bootstrap;
CockpitManager.prototype.bootstrap = async function\(\) {
  const originalRequest = this.deck._request;
  let labelCount = 0;
  let assignCount = 0;

  this.deck._request = async function\(method, path, body\) {
    const result = await originalRequest.call\(this, method, path, body\);

    if \(method === 'POST' && path.includes\('/labels'\)\) {
      labelCount++;
      console.log\(`Label ${labelCount}: title="${result.title}" id=${result.id}`\);
    }

    if \(method === 'PUT' && path.includes\('/assignLabel'\)\) {
      assignCount++;
      console.log\(`ASSIGN #${assignCount}: labelId=${body.labelId}`\);
    }

    return result;
  };

  const result = await original.call\(this\);

  console.log\(`\\nSummary: ${labelCount} labels created, ${assignCount} labels assigned`\);

  return result;
};

const createMockDeckClient = \(overrides = {}\) => {
  const calls = [];
  const BOARD_TITLE = 'Moltagent Cockpit';
  const mock = {
    _calls: calls,
    nc: {},
    baseUrl: 'https://cloud.example.com',
    username: 'moltagent',
    listBoards: async \(\) => { calls.push\({ method: 'listBoards' }\); return overrides.listBoards || []; },
    getBoard: async \(boardId\) => { calls.push\({ method: 'getBoard', boardId }\); return overrides.getBoard || { id: boardId, title: BOARD_TITLE, stacks: [], labels: [] }; },
    getStacks: async \(boardId\) => { calls.push\({ method: 'getStacks', boardId }\); return overrides.getStacks || []; },
    createStack: async \(boardId, title, order\) => { calls.push\({ method: 'createStack', boardId, title, order }\); return { id: 100 + order, title, order }; },
    shareBoard: async \(\) => { return { id: 1 }; },
    _request: async \(method, path, body\) => {
      calls.push\({ method: '_request', httpMethod: method, path, body }\);
      if \(method === 'POST' && path.includes\('/boards'\) && !path.includes\('/stacks'\)\) return { id: 99, title: BOARD_TITLE };
      if \(method === 'POST' && path.includes\('/labels'\)\) return { id: 200 + calls.length, title: body?.title || 'label', color: body?.color };
      if \(method === 'POST' && path.includes\('/cards'\)\) return { id: 300 + calls.length, title: body?.title || 'card' };
      if \(method === 'PUT' && path.includes\('/assignLabel'\)\) return { success: true };
      if \(method === 'DELETE'\) return { success: true };
      return {};
    }
  };
  return mock;
};

const deck = createMockDeckClient\(\);
const cm = new CockpitManager\({ deckClient: deck }\);

cm.bootstrap\(\).then\(\(\) => {
  console.log\('Done!'\);
}\).catch\(err => console.error\('ERROR:', err.message\)\);
ENDSCRIPT)
